package main

import (
	"bufio"
	"fmt"
	"os"
	"strconv"
	"strings"
)

type Node struct {
	Value int
	next  *Node
	prev  *Node
	root  *Node
}

type LList struct {
	root *Node
	size int
}

func NewLList() *LList {
	list := &LList{}
	list.root = &Node{root: nil}
	list.root.next = list.root
	list.root.prev = list.root
	list.root.root = list.root // nó sentinela aponta pra si mesmo
	return list
}

func (l *LList) PushBack(value int) {
	l.insertBefore(l.root, value)
	l.size++
}

func (l *LList) insertBefore(mark *Node, value int) {
	n := &Node{
		Value: value,
		root:  l.root,
	}
	n.prev = mark.prev
	n.next = mark
	mark.prev.next = n
	mark.prev = n
}


func str2list(serial string) *LList {
	serial = serial[1 : len(serial)-1]
	ll := NewLList()
	if serial == "" {
		return ll
	}
	for _, p := range strings.Split(serial, ",") {
		value, _ := strconv.Atoi(p)
		ll.PushBack(value)
	}
	return ll
}

func equals(lla *LList, llb *LList) bool {
	if lla.size!=llb.size {
		return false
	}

	for nodeA, nodeB := lla.root.next, llb.root.next; nodeA!=lla.root; nodeA, nodeB = nodeA.next, nodeB.next {
		if nodeA.Value!=nodeB.Value {
			return false
		}
	}
	return true
}

func reverse(ll *LList) {
	node := ll.root

	for {
		node.next, node.prev = node.prev, node.next
		node = node.prev

		if node == ll.root {
			break
		}
	}
}

func (l *LList) String() string {
	var sb strings.Builder

	sb.WriteString("[")

	for n := l.root.next; n != l.root; n = n.next {
		sb.WriteString(strconv.Itoa(n.Value))

		if n.next != l.root {
			sb.WriteString(", ")
		}
	}

	sb.WriteString("]")
	return sb.String()
}

func addsorted(l *LList, value int) {
	for node := l.root.next; node != l.root; node = node.next {
		if value <= node.Value {
			l.insertBefore(node, value)
			l.size++
			return
		}
	}
	l.insertBefore(l.root, value)
	l.size++
}

func merge(lla *LList, llb *LList) *LList {
	for node := llb.root.next; node!=llb.root; node = node.next {
		addsorted(lla, node.Value)
	}
	return lla
}

func main() {
	scanner := bufio.NewScanner(os.Stdin)

	for {
		fmt.Print("$")
		if !scanner.Scan() {
			break
		}
		line := scanner.Text()
		fmt.Println(line)
		args := strings.Fields(line)

		if len(args) == 0 {
			continue
		}

		cmd := args[0]

		switch cmd {
		case "compare":
			lla := str2list(args[1])
			llb := str2list(args[2])
			if equals(lla, llb) {
				fmt.Println("iguais")
			} else {
				fmt.Println("diferentes")
			}
		case "addsorted":
			lla := NewLList()
			for i := 1; i < len(args); i++ {
				value, _ := strconv.Atoi(args[i])
				addsorted(lla, value)
			}
			fmt.Println(lla.String())
		case "reverse":
			lla := str2list(args[1])
			reverse(lla)
			fmt.Println(lla.String())
		case "merge":
			lla := str2list(args[1])
			llb := str2list(args[2])
			merged := merge(lla, llb)
			fmt.Println(merged)
		case "end":
			return
		default:
			fmt.Println("fail: comando invalido")
		}
	}
}
